var authGuard = (route, state2) => {
  const router = inject(Router);
  let token = null;
  if (typeof window !== "undefined" && localStorage) {
    token = localStorage.getItem("authToken");
  }
  if (token) {
    router.navigate(["/home"]);
    return false;
  }
  return true;
};

